extern @abi(c-msvc-x64) fn vec_u64_push(id: u64, v: u64) -> i32 from "vec.iii"
extern @abi(c-msvc-x64) fn vec_u64_at(id: u64, i: u64) -> u64 from "vec.iii"
extern @abi(c-msvc-x64) fn vec_u64_count(id: u64) -> u64 from "vec.iii"

fn main() -> u64 {
    /* --- vec_safe_cap: positive cases --------------------------------- */

    /* Need 9, cur_cap 8, hard_max 64 -> cap doubles once to 16. */
    let c1 : u64 = vec_safe_cap(8u64, 9u64, 64u64)
    if c1 != 16u64 { return 1u64 }

    /* Need exactly equal to cur_cap: no doubling needed, returns cur_cap. */
    let c2 : u64 = vec_safe_cap(16u64, 16u64, 64u64)
    if c2 != 16u64 { return 2u64 }

    /* Need 1, cur_cap 0 (coerced to 1 inside helper), hard_max 8 -> 1 >= 1. */
    let c3 : u64 = vec_safe_cap(0u64, 1u64, 8u64)
    if c3 == 0u64 { return 3u64 }

    /* Need equals hard_max exactly: must return hard_max, not 0. */
    let c4 : u64 = vec_safe_cap(4u64, 8u64, 8u64)
    if c4 != 8u64 { return 4u64 }

    /* --- vec_safe_cap: NEGATIVE -- overflow guard fires --------------- */

    /* need > hard_max: must return 0 (overflow sentinel). */
    let neg1 : u64 = vec_safe_cap(8u64, 100u64, 50u64)
    if neg1 != 0u64 { return 5u64 }

    /* hard_max = 1, cur_cap = 1, need = 1: cur_cap >= need already, returns 1. */
    let c5 : u64 = vec_safe_cap(1u64, 1u64, 1u64)
    if c5 != 1u64 { return 6u64 }

    /* Pathological: hard_max near U64_MAX, need = hard_max, cur_cap = hard_max/2 + 1.
     * Next double of cur_cap would overflow.  Saturation path: nc = hard_max.
     * hard_max = 0xFFFFFFFFFFFFFFF0u64 */
    let huge_max : u64 = 0xFFFFFFFFFFFFFFF0u64
    let huge_cur : u64 = 0x8000000000000001u64   /* > huge_max/2 */
    let c6 : u64 = vec_safe_cap(huge_cur, huge_cur, huge_max)
    /* cur_cap >= need already (huge_cur == need), so no iteration, returns huge_cur clamped to huge_max. */
    if c6 != huge_cur { return 7u64 }

    /* Force the saturation branch: cur_cap = 0x8000000000000001 (> huge_max/2),
     * need = huge_cur + 1.  Iteration: nc > hard_max/2 -> nc = hard_max.
     * Then nc (= huge_max) >= need (= huge_cur+1)?  huge_max > huge_cur, yes.
     * Result = huge_max. */
    let huge_need : u64 = huge_cur + 1u64
    let c7 : u64 = vec_safe_cap(huge_cur, huge_need, huge_max)
    if c7 != huge_max { return 8u64 }

    /* --- vec_safe_bytes: positive cases ------------------------------- */

    /* 8 * 8 = 64. */
    let b1 : u64 = vec_safe_bytes(8u64, 8u64)
    if b1 != 64u64 { return 9u64 }

    /* 0 * 8 = 0 (zero cap: 0 bytes). */
    let b2 : u64 = vec_safe_bytes(0u64, 8u64)
    if b2 != 0u64 { return 10u64 }

    /* esz = 0: always 0 (degenerate). */
    let b3 : u64 = vec_safe_bytes(100u64, 0u64)
    if b3 != 0u64 { return 11u64 }

    /* cap = 0x1000000000000000u64, esz = 8: product = 0x8000000000000000u64 (fits). */
    let b4 : u64 = vec_safe_bytes(0x1000000000000000u64, 8u64)
    if b4 != 0x8000000000000000u64 { return 12u64 }

    /* --- vec_safe_bytes: NEGATIVE -- overflow guard fires ------------- */

    /* cap = 0x2000000000000001u64, esz = 8:
     * 0x2000000000000001 * 8 = 0x10000000000000008 -> overflows u64.
     * Guard: cap > U64_MAX / 8 = 0x1FFFFFFFFFFFFFFFu64, yes -> return 0. */
    let neg2 : u64 = vec_safe_bytes(0x2000000000000001u64, 8u64)
    if neg2 != 0u64 { return 13u64 }

    /* cap = U64_MAX, esz = 2: U64_MAX * 2 overflows.
     * Guard: U64_MAX > U64_MAX / 2 = 0x7FFFFFFFFFFFFFFFu64, yes -> return 0. */
    let neg3 : u64 = vec_safe_bytes(0xFFFFFFFFFFFFFFFFu64, 2u64)
    if neg3 != 0u64 { return 14u64 }

    /* --- Integration: vec_u8 grows through cap 8 -> 16 --------------- */

    let a : u64 = arena_new(4096u64)
    if a == 0u64 { return 20u64 }

    /* Create with hard_max=32, init_cap=8. */
    let v : u64 = vec_u8_new(a, 32u64)
    if v == 0u64 { return 21u64 }
    if vec_u8_capacity(v) != 8u64 { return 22u64 }

    /* Push 12 bytes: forces a grow from cap 8 to cap 16 on push #9. */
    let mut pi : u32 = 0u32
    while pi < 12u32 {
        if vec_u8_push(v, pi) != 0i32 { return 23u64 }
        pi = pi + 1u32
    }
    if vec_u8_len(v) != 12u64 { return 24u64 }
    if vec_u8_capacity(v) != 16u64 { return 25u64 }

    /* Verify data integrity across the grow boundary. */
    if vec_u8_at(v, 0u64) != 0u32 { return 26u64 }
    if vec_u8_at(v, 7u64) != 7u32 { return 27u64 }
    if vec_u8_at(v, 8u64) != 8u32 { return 28u64 }
    if vec_u8_at(v, 11u64) != 11u32 { return 29u64 }

    /* --- Integration: vec_u64 push/at after grow ---------------------- */

    let w : u64 = vec_u64_new(a, 32u64)
    if w == 0u64 { return 30u64 }

    /* Push 10 u64 values: forces grow at push #9. */
    let mut qi : u64 = 0u64
    while qi < 10u64 {
        if vec_u64_push(w, qi * 1000u64) != 0i32 { return 31u64 }
        qi = qi + 1u64
    }
    if vec_u64_count(w) != 10u64 { return 32u64 }
    if vec_u64_at(w, 0u64) != 0u64 { return 33u64 }
    if vec_u64_at(w, 9u64) != 9000u64 { return 34u64 }

    arena_drop(a)
    return 99u64
}
